scwin.f_ExistSameRowYn = function (dataList, colArray) {
  if (dataList == null || colArray == null) return false;
  if (dataList.getRowCount() <= 1) return false;
  for (let i = 0; i < dataList.getRowCount() - 1; i++) {
    for (let j = i + 1; j < dataList.getRowCount(); j++) {
      if (i == j) continue;
      if (scwin.f_getRowDataStr(dataList, i, colArray) == scwin.f_getRowDataStr(dataList, j, colArray)) {
        return true;
      }
    }
  }
  return false;
};
scwin.f_getRowDataStr = function (dataList, row, colArray) {
  if (dataList == null || colArray == null || row == null) return "";
  if (!scwin.f_IsArray(colArray)) return "";
  if (row < 0) return "";
  let retArray = [];
  for (let i = 0; i < colArray.length; i++) {
    retArray[retArray.length] = dataList.getCellData(row, colArray[i]);
  }
  return retArray.toString();
};
